
if not bit32 then
  bit32 = {}
  function bit32.bxor(a, b)
    local r, bit = 0, 1
    while a > 0 or b > 0 do
      local ab, bb = a % 2, b % 2
      if ab ~= bb then r = r + bit end
      a = (a - ab) / 2; b = (b - bb) / 2; bit = bit * 2
    end
    return r
  end
end

